CREATE TABLE IF NOT EXISTS metrics (ts INTEGER PRIMARY KEY, fps REAL NOT NULL, frametime_ms REAL NOT NULL, players INTEGER NOT NULL);
CREATE TABLE IF NOT EXISTS metrics_rollup (ts INTEGER PRIMARY KEY, fps_avg REAL, fps_min REAL, fps_max REAL, frametime_avg REAL, frametime_min REAL, frametime_max REAL, players_avg REAL, players_min INTEGER, players_max INTEGER);
CREATE TABLE IF NOT EXISTS players (uid TEXT PRIMARY KEY, steam_id TEXT NOT NULL DEFAULT '', name TEXT NOT NULL DEFAULT '', account_name TEXT NOT NULL DEFAULT '', first_seen INTEGER, last_seen INTEGER, playtime_sec INTEGER NOT NULL DEFAULT 0, banned INTEGER NOT NULL DEFAULT 0, whitelisted INTEGER NOT NULL DEFAULT 0, level INTEGER NOT NULL DEFAULT 0, guild_id TEXT NOT NULL DEFAULT '', guild_name TEXT NOT NULL DEFAULT '', ping REAL NOT NULL DEFAULT 0, location_x REAL, location_y REAL, raw_json TEXT NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS sessions (id INTEGER PRIMARY KEY AUTOINCREMENT, player_uid TEXT NOT NULL, join_at INTEGER NOT NULL, leave_at INTEGER);
CREATE TABLE IF NOT EXISTS events (id INTEGER PRIMARY KEY AUTOINCREMENT, at INTEGER NOT NULL, kind TEXT NOT NULL, message TEXT NOT NULL, meta_json TEXT NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS saved_commands (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, command TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS console_log (id INTEGER PRIMARY KEY AUTOINCREMENT, at INTEGER NOT NULL, user TEXT NOT NULL, command TEXT NOT NULL, output TEXT NOT NULL, is_error INTEGER NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS kv (key TEXT PRIMARY KEY, value TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS guilds (id TEXT PRIMARY KEY, name TEXT, admin_uid TEXT, raw_json TEXT NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS guild_members (guild_id TEXT, player_uid TEXT, name TEXT, PRIMARY KEY(guild_id, player_uid));
CREATE TABLE IF NOT EXISTS bases (id TEXT PRIMARY KEY, guild_id TEXT, x REAL, y REAL, level INTEGER NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS pals (instance_id TEXT PRIMARY KEY, owner_uid TEXT, character_id TEXT, display_name TEXT NOT NULL DEFAULT '', level INTEGER, is_alpha INTEGER, is_lucky INTEGER, raw_json TEXT NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS world_state (singleton INTEGER PRIMARY KEY CHECK(singleton=1), day INTEGER, last_parse_at INTEGER, parse_duration_ms INTEGER, players INTEGER, pals INTEGER, guilds INTEGER, skipped_props INTEGER, format_drift INTEGER);
CREATE TABLE IF NOT EXISTS whitelist (steam_id TEXT PRIMARY KEY, name TEXT NOT NULL DEFAULT '');
CREATE TABLE IF NOT EXISTS backups (id INTEGER PRIMARY KEY AUTOINCREMENT, file TEXT NOT NULL UNIQUE, created_at INTEGER NOT NULL, size_bytes INTEGER NOT NULL, trigger TEXT NOT NULL, world_day INTEGER);
INSERT OR IGNORE INTO kv(key,value) VALUES('schema_version','1');
CREATE INDEX IF NOT EXISTS metrics_ts ON metrics(ts);
CREATE INDEX IF NOT EXISTS events_at ON events(at DESC);
CREATE INDEX IF NOT EXISTS sessions_uid ON sessions(player_uid, join_at DESC);
